#include <stdio.h>
#include <stdlib.h>
#include <limits.h>
#define N 100001
#define INF 1000000000000000000LL
#define MAX_M 100000

typedef struct Edge {
    int to;
    int weight;
    struct Edge* next;
} Edge;

Edge* edges[N];

void addEdge(int from, int to, int weight) {
    Edge* newEdge = (Edge*)malloc(sizeof(Edge));
    newEdge->to = to;
    newEdge->weight = weight;
    newEdge->next = edges[from];
    edges[from] = newEdge;
}

long long dijkstra(int n, int start, int end) {
    long long distances[N];
    for (int i = 0; i < n; i++) {
        distances[i] = INF;
    }
    distances[start] = 0;

    int visited[N];
    for (int i = 0; i < n; i++) {
        visited[i] = 0;
    }

    for (int i = 0; i < n - 1; i++) {
        int minDistance = INF;
        int minIndex = -1;
        for (int j = 0; j < n; j++) {
            if (!visited[j] && distances[j] < minDistance) {
                minDistance = distances[j];
                minIndex = j;
            }
        }

        visited[minIndex] = 1;

        Edge* currentEdge = edges[minIndex];
        while (currentEdge != NULL) {
            if (!visited[currentEdge->to] && distances[minIndex] + currentEdge->weight < distances[currentEdge->to]) {
                distances[currentEdge->to] = distances[minIndex] + currentEdge->weight;
            }
            currentEdge = currentEdge->next;
        }
    }

    return distances[end];
}

int main() {
    int t;
    scanf("%d", &t);
    while (t--) {
        int n, m;
        scanf("%d %d", &n, &m);
        int s, t, v;
        scanf("%d %d %d", &s, &t, &v);

        for (int i = 0; i < n; i++) {
            edges[i] = NULL;
        }

        for (int i = 0; i < m; i++) {
            int a, b, c;
            scanf("%d %d %d", &a, &b, &c);
            addEdge(a - 1, b - 1, c);
            addEdge(b - 1, a - 1, c);
        }

        long long distance1 = dijkstra(n, s - 1, v - 1);
        long long distance2 = dijkstra(n, v - 1, t - 1);

        printf("%lld\n", distance1 + distance2);
    }
    return 0;
}

