import java.util.*;
public class Main {
    static final int N = 100001;
    static final long INF = (long)1e18;
    static ArrayList<int[]>[] edges;

    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int t = sc.nextInt();
        while (t-- > 0) {
            int n = sc.nextInt();
            int m = sc.nextInt();
            int s = sc.nextInt();
            int t = sc.nextInt();
            int v = sc.nextInt();

            edges = new ArrayList[n];
            for (int i = 0; i < n; i++) {
                edges[i] = new ArrayList<>();
            }

            for (int i = 0; i < m; i++) {
                int a = sc.nextInt();
                int b = sc.nextInt();
                int c = sc.nextInt();
                edges[a - 1].add(new int[] {b - 1, c});
                edges[b - 1].add(new int[] {a - 1, c});
            }

            long distance1 = dijkstra(n, s - 1, v - 1);
            long distance2 = dijkstra(n, v - 1, t - 1);

            System.out.println(distance1 + distance2);
        }
    }

    public static long dijkstra(int n, int start, int end) {
        long[] distances = new long[n];
        Arrays.fill(distances, INF);
        distances[start] = 0;

        boolean[] visited = new boolean[n];

        for (int i = 0; i < n - 1; i++) {
            int minDistance = (int)INF;
            int minIndex = -1;
            for (int j = 0; j < n; j++) {
                if (!visited[j] && distances[j] < minDistance) {
                    minDistance = (int)distances[j];
                    minIndex = j;
                }
            }

            visited[minIndex] = true;

            for (int[] edge : edges[minIndex]) {
                if (!visited[edge[0]] && distances[minIndex] + edge[1] < distances[edge[0]]) {
                    distances[edge[0]] = distances[minIndex] + edge[1];
                }
            }
        }

        return distances[end];
    }
}

