function dijkstra(n, start, end) {
    const distances = Array(n).fill(INF);
    distances[start] = 0;

    const visited = Array(n).fill(false);

    for (let i = 0; i < n - 1; i++) {
        let minDistance = INF;
        let minIndex = -1;
        for (let j = 0; j < n; j++) {
            if (!visited[j] && distances[j] < minDistance) {
                minDistance = distances[j];
                minIndex = j;
            }
        }

        visited[minIndex] = true;

        for (const [to, weight] of edges[minIndex]) {
            if (!visited[to] && distances[minIndex] + weight < distances[to]) {
                distances[to] = distances[minIndex] + weight;
            }
        }
    }

    return distances[end];
